// 设置默认时间配置 SchedulerProperties properties = SchedulerProperties.defaultProperties(); TaskRegistry registry = new TaskRegistry(); // 线程数按当前 5 个后台进程加一点余量设置。HDP 正式实现可以统一接入项目线程池。 ScheduledExecutorService scheduler = Executors.newScheduledThreadPool(6); // TODO: 迁移到 HDP 后，这里应加载 core-site.xml、hdfs-site.xml、yarn-site.xml、Kerberos 等真实配置。 Configuration hadoopConfiguration = new Configuration(); HadoopHdfsTaskDefinitionRepository hdfsRepository = new HadoopHdfsTaskDefinitionRepository(properties, hadoopConfiguration); HadoopYarnApplicationClient yarnClient = new HadoopYarnApplicationClient(hadoopConfiguration); // 1. 任务发现：只负责维护 daily/interval 内存实例。 TaskDiscoverySyncService discoverySyncService = new TaskDiscoverySyncService(registry, hdfsRepository, yarnClient, properties); // 2. daily 到点触发：只负责每分钟看时间，到点后提交 SINGLE 任务。 DailyTriggerSchedulerService dailyTriggerSchedulerService = new DailyTriggerSchedulerService(registry, properties); // 3. daily 配置刷新：按小时同步启动时间等配置，和任务发现同步分开。 DailyTriggerConfigRefreshService dailyTriggerConfigRefreshService = new DailyTriggerConfigRefreshService(registry, hdfsRepository, properties); // 4. interval 常驻管理：负责拉起和重启 POLLING 任务。 IntervalTaskManagerService intervalTaskManagerService = new IntervalTaskManagerService(registry, properties); // 5. interval 状态监控：负责从 YARN 同步真实运行状态。 IntervalYarnMonitorService intervalYarnMonitorService = new IntervalYarnMonitorService(registry, yarnClient, properties); // 启动顺序可以按“先发现、再调度/监控”理解。 discoverySyncService.start(scheduler); dailyTriggerSchedulerService.start(scheduler); dailyTriggerConfigRefreshService.start(scheduler); intervalTaskManagerService.start(scheduler); intervalYarnMonitorService.start(scheduler); // 示例：HDP 中 MML 命令入口拿到 StartTask(taskA) 后，可以这样接进来。 // sparkClientUDA.asynchExecuteTask(EVENT_TRIGGER:taskA,hdfs://hacluster/UDA/event_trigger/taskA)